type SvgIconProps = {
    name: keyof typeof paths;
    size?: number;
    className?: string;
    style?: React.CSSProperties;
};

export default function SvgIcon({ name, size = 24, className = "", style }: SvgIconProps) {
    const content = paths[name];
    if (!content) return null;
    return (
        <svg
            width={size}
            height={size}
            viewBox="0 0 24 24"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
            className={className}
            style={style}
            aria-hidden="true"
        >
            {content}
        </svg>
    );
}
